import{_ as e,o as a,c as t,a as n}from"./app.014522ac.js";const m=JSON.parse('{"title":"Case History and Precedents","description":"","frontmatter":{},"headers":[{"level":2,"title":"TheOrangeWizard v. 14uu, Aug 2017","slug":"theorangewizard-v-14uu-aug-2017","link":"#theorangewizard-v-14uu-aug-2017","children":[]},{"level":2,"title":"1machinemaker1 v. 14uu, Aug 2017","slug":"_1machinemaker1-v-14uu-aug-2017","link":"#_1machinemaker1-v-14uu-aug-2017","children":[]},{"level":2,"title":"Crustifer v. SpicyBoy, Oct 2017","slug":"crustifer-v-spicyboy-oct-2017","link":"#crustifer-v-spicyboy-oct-2017","children":[]},{"level":2,"title":"Yoahtl v. 14uu, Oct 2017","slug":"yoahtl-v-14uu-oct-2017","link":"#yoahtl-v-14uu-oct-2017","children":[]},{"level":2,"title":"14uu v. 5point0, Nov 2017","slug":"_14uu-v-5point0-nov-2017","link":"#_14uu-v-5point0-nov-2017","children":[]},{"level":2,"title":"Yoahtl v. 1machinemaker1, Nov 2017","slug":"yoahtl-v-1machinemaker1-nov-2017","link":"#yoahtl-v-1machinemaker1-nov-2017","children":[]},{"level":2,"title":"Yoahtl v. Fran, Nov 2017","slug":"yoahtl-v-fran-nov-2017","link":"#yoahtl-v-fran-nov-2017","children":[]},{"level":2,"title":"Yoahtl v. Link2006, Nov 2017","slug":"yoahtl-v-link2006-nov-2017","link":"#yoahtl-v-link2006-nov-2017","children":[]},{"level":2,"title":"1machinemaker1 v. Yoahtl, Nov 2017","slug":"_1machinemaker1-v-yoahtl-nov-2017","link":"#_1machinemaker1-v-yoahtl-nov-2017","children":[]}],"relativePath":"government/court-cases-precedents/index.md","lastUpdated":1665949328000}'),i={name:"government/court-cases-precedents/index.md"},o=n('<h1 id="case-history-and-precedents" tabindex="-1">Case History and Precedents <a class="header-anchor" href="#case-history-and-precedents" aria-hidden="true">#</a></h1><p>This is a record of all the court cases in Yoahtl. Our court system works via an ever evolving set of decisions, by the Councillors acting in their capacity as judges in legal disputes. The precedent they set in court has the force of law, but can be challenged by concerned parties. If a separate judicial system were to arise, the existing case precedent would carry over to the new judiciary, since the courts would still be of the same legal essence. Not all decisions create precedent, only those trying new matters.</p><h2 id="theorangewizard-v-14uu-aug-2017" tabindex="-1"><a href="/government/court-cases-precedents/orange_v_14uu_aug_2017.html">TheOrangeWizard v. 14uu, Aug 2017</a> <a class="header-anchor" href="#theorangewizard-v-14uu-aug-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Confirmed the Extinction Rule that unauthorized construction except for underneath a plot one owned is not considered valid unless the Government has approved of the action.</li><li>Grief is to be punished by having the griefer clean it up.</li></ul><h2 id="_1machinemaker1-v-14uu-aug-2017" tabindex="-1"><a href="/government/court-cases-precedents/1machinemaker1_v_14uu_aug_2017.html">1machinemaker1 v. 14uu, Aug 2017</a> <a class="header-anchor" href="#_1machinemaker1-v-14uu-aug-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Restitution of all items in cases of two-sided disputes is standard practice.</li><li>The person found to be more guilty in a two-sided dispute can be put on probation (pearled and summoned) if the court believes them to have been at fault.</li></ul><h2 id="crustifer-v-spicyboy-oct-2017" tabindex="-1"><a href="/government/court-cases-precedents/crustifer_v_spicyboy_oct_2017.html">Crustifer v. SpicyBoy, Oct 2017</a> <a class="header-anchor" href="#crustifer-v-spicyboy-oct-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Theft will be met with forced restitution.</li><li>Searching a house for contraband is a valid tactic to find evidence for trials.</li><li>Repeated offenses of the same category can be punished more severely.</li></ul><h2 id="yoahtl-v-14uu-oct-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_14uu_oct_2017.html">Yoahtl v. 14uu, Oct 2017</a> <a class="header-anchor" href="#yoahtl-v-14uu-oct-2017" aria-hidden="true">#</a></h2><h2 id="_14uu-v-5point0-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/14uu_v_5point0_nov_2017.html">14uu v. 5point0, Nov 2017</a> <a class="header-anchor" href="#_14uu-v-5point0-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>An extreme imbalance of capability during a physical altercation means that the person in a stronger position has a responsibility to be more mature.</li><li>Meming is not an excuse for violence if both parties aren&#39;t in on the meme.</li></ul><h2 id="yoahtl-v-1machinemaker1-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_1machinemaker1_nov_2017.html">Yoahtl v. 1machinemaker1, Nov 2017</a> <a class="header-anchor" href="#yoahtl-v-1machinemaker1-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>Insubordination is defined as a refusal to follow instructions when working with public property, sanctioned or unsanctioned.</li><li>Roads count as public property.</li></ul><h2 id="yoahtl-v-fran-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_fran_nov_2017.html">Yoahtl v. Fran, Nov 2017</a> <a class="header-anchor" href="#yoahtl-v-fran-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>If you are hired by a private citizen to do something and they tell you to stop, you stop.</li><li>It&#39;s not a deathtrap if it&#39;s not even finished and serving its intended purpose in the first place.</li></ul><h2 id="yoahtl-v-link2006-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/yoahtl_v_link2006_nov_2017.html">Yoahtl v. Link2006, Nov 2017</a> <a class="header-anchor" href="#yoahtl-v-link2006-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li><p>No matter the charges, unless you are being directly attacked or the town is being griefed, or it is a hostile foreigner, no player other than Councillors or the Alcuahtl or any person occupying a position of authority to pearl legally authorized by the Council and Alcuahtl may pearl people.</p></li><li><p>If people plead guilty you retain the rights of a citizen unless the Judge explicitly denies them to you as a result of your actions.</p></li></ul><h2 id="_1machinemaker1-v-yoahtl-nov-2017" tabindex="-1"><a href="/government/court-cases-precedents/1machinemaker1_v_yoahtl_nov_2017.html">1machinemaker1 v. Yoahtl, Nov 2017</a> <a class="header-anchor" href="#_1machinemaker1-v-yoahtl-nov-2017" aria-hidden="true">#</a></h2><p>Precedents:</p><ul><li>The Alcuahtl cannot deny an appeal outright, only uphold the decision of the court or come to a new verdict.</li></ul>',27),r=[o];function l(s,h,c,u,d,v){return a(),t("div",null,r)}const y=e(i,[["render",l]]);export{m as __pageData,y as default};
